draw((0,0)--(1,4)--(7,4)--(12,0)--cycle);
draw((5,0)--(7,4));
draw((1,4)--(5.5,4)--(5.5,0)--(1,0)--cycle,dashed);
label("$RS=7$", (7,4)--(5.5,4),NE);
label("$PQ=1$", (1,0)--(5.5,0),E);
